import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const MyTasks = () => {
  const { user } = useAuth();
  const { tasks, updateTaskProgress } = useData();
  const [tempReasons, setTempReasons] = useState({});

  const myTasks = tasks.filter(t => t.assigneeId === user.id);

  const handleConfirmUpdate = (taskId, currentProgress) => {
    const reason = tempReasons[taskId] || '';
    if (currentProgress < 90 && !reason.trim()) {
      alert("Thông báo: Bạn bắt buộc phải nhập lý do giải thích khi mức độ hoàn thành dưới 90%!");
      return;
    }
    updateTaskProgress(taskId, currentProgress, reason);
    alert("Cập nhật tiến độ thành công!");
  };

  return (
    <div>
      <h2>Công việc của tôi</h2>
      {myTasks.length === 0 ? <p>Hiện chưa có công việc được giao.</p> : (
        <div style={{ display: 'grid', gap: '20px' }}>
          {myTasks.map(task => {
            // Logic kiểm tra quá hạn
            const today = new Date();
            const deadlineDate = new Date(task.deadline);
            // So sánh: Nếu hôm nay > deadline VÀ chưa hoàn thành (progress < 100)
            const isOverdue = today > deadlineDate && task.progress < 100;

            return (
              <div key={task.id} style={{ border: '1px solid #ccc', padding: '20px', borderRadius: '8px', background: 'white', position: 'relative' }}>
                
                {/* [MỚI] Hiển thị thông báo kỷ luật nếu quá hạn */}
                {isOverdue && (
                  <div style={{ 
                    background: '#ffe6e6', 
                    border: '1px solid red', 
                    color: '#cc0000', 
                    padding: '10px', 
                    borderRadius: '5px', 
                    marginBottom: '15px',
                    fontWeight: 'bold',
                    textAlign: 'center'
                  }}>
                    ⚠️ CẢNH BÁO: ĐÃ QUÁ HẠN DEADLINE! <br/>
                    HÌNH THỨC KỶ LUẬT ĐÃ ĐƯỢC ÁP DỤNG: {task.discipline.toUpperCase()}
                  </div>
                )}

                <h3 style={{ marginTop: 0 }}>{task.title}</h3>
                <p><strong>Thời gian:</strong> {task.startDate} đến <strong>{task.deadline}</strong></p>
                
                <label>Mức độ hoàn thành: <strong>{task.progress}%</strong></label>
                <input 
                  type="range" 
                  min="0" max="100" 
                  value={task.progress} 
                  onChange={(e) => updateTaskProgress(task.id, parseInt(e.target.value), task.reason)}
                  style={{ width: '100%', marginTop: '10px' }}
                  disabled={task.progress === 100} 
                />

                {task.progress < 90 && task.progress !== 100 && (
                  <div style={{ marginTop: '15px' }}>
                    <p style={{ color: 'orange', fontSize: '0.9rem', marginBottom: '5px' }}>
                      * Tiến độ dưới 90% cần nhập lý do
                    </p>
                    <textarea
                      placeholder="Nhập lý do tại đây..."
                      value={tempReasons[task.id] !== undefined ? tempReasons[task.id] : task.reason}
                      onChange={(e) => setTempReasons({ ...tempReasons, [task.id]: e.target.value })}
                      style={{ width: '100%', height: '60px', padding: '8px' }}
                    />
                  </div>
                )}

                <button 
                  onClick={() => handleConfirmUpdate(task.id, task.progress)}
                  style={{ 
                    marginTop: '15px', 
                    padding: '10px 25px', 
                    background: '#1890ff', 
                    color: 'white', 
                    border: 'none', 
                    borderRadius: '4px', 
                    cursor: 'pointer',
                    fontWeight: 'bold'
                  }}
                >
                  Cập nhật tiến độ
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default MyTasks;
